export function pop(): number | undefined {
  // 如果 s2 为空，则将栈 s1 中的内容弹出并压入栈 s2 中
  if (s2.length <= 0) {
    while (s1.length > 0) s2.push(s1.pop())
  }

  // 从 s2 中弹栈的值遵循原序列的先入先出规则
  return s2.pop()
}

export function Fibonacci(n: number): number {
  if (n <= 1) return n

  let a = 0
  let b = 1
  let c = 1
  for (let i = 3; i <= n; ++i) {
    a = b
    b = c
    c = a + b
  }
  return c
}

export function jumpFloor(n: number): number {
  if (n <= 0) return 0
  if (n <= 2) return n

  let a = 1
  let b = 2
  let c = 3
  for (let i = 3; i < n; ++i) {
    a = b
    b = c
    c = a + b
  }
  return c
}

export function jumpFloorII(n: number): number {
  if (n <= 0) return 0
  return 1 << (n - 1)
}

export function rectCover(n: number): number {
  if (n <= 0) return 0
  if (n <= 2) return n

  let a = 1
  let b = 2
  let c = 3
  for (let i = 3; i < n; ++i) {
    a = b
    b = c
    c = a + b
  }
  return c
}

