export function FindKthToTail(pHead: ListNode, k: number) {
  let faster = pHead
  let slower = pHead

  // 快指针先走 k 步
  for (let step = 0; step < k; ++step) {
    if (faster == null) return null
    faster = faster.next
  }

  // 两个指针一起走
  while (faster != null) {
    faster = faster.next
    slower = slower.next
  }
  return slower
}

