export function ReverseList(pHead: ListNode): ListNode {
  if (pHead == null) return null

  let x: ListNode | null = pHead
  let y: ListNode | null = pHead.next
  while (y != null) {
    const z = y.next
    y.next = x
    x = y
    y = z
  }
  pHead.next = null
  return x
}

