export function Merge(pHead1: ListNode, pHead2: ListNode): ListNode {
  const fakeRoot: ListNode = {
    val: -1,
    next: null,
  }

  let x: ListNode = pHead1
  let y: ListNode = pHead2
  let z: ListNode = fakeRoot
  for (; x != null && y != null; z = z.next) {
    if (x.val < y.val) {
      z.next = x
      x = x.next
    } else {
      z.next = y
      y = y.next
    }
  }

  if (x != null) z.next = x
  if (y != null) z.next = y
  return fakeRoot.next
}

