export function PrintFromTopToBottom(root: TreeNode): number[] {
  if (root == null) return []
  const Q: TreeNode[] = []
  const result: number[] = []
  Q.push(root)
  while (Q.length > 0) {
    const x = Q.shift()
    result.push(x.val)
    if (x.left) Q.push(x.left)
    if (x.right) Q.push(x.right)
  }
  return result
}

