interface PriorityQueue<T> {
  enqueue: (val: T) => void
  dequeue: () => T | undefined
  collect: () => T[]
  top: () => T | undefined
  size: () => number
  isEmpty: () => boolean
}

// 优先队列
function createPriorityQueue<T>(
  cmp: (x: T, y: T) => -1 | 0 | 1 | number,
): PriorityQueue<T> {
  const _tree: T[] = [null]
  let _size: number = 0

  function enqueue(val: T): void {
    _tree[++_size] = val
    _up(_size)
  }

  function dequeue(): T | undefined {
    if (_size < 1) return undefined

    const target = _tree[1]
    _tree[1] = _tree[_size--]
    _down(1)

    return target
  }

  function top(): T | undefined {
    return _size > 0 ? _tree[1] : undefined
  }

  function collect(): T[] {
    return _tree.slice(1)
  }

  function _down(index: number): void {
    for (let i = index; i <= _size; ) {
      const lft = i << 1
      const rht = lft | 1
      if (lft > _size) break

      let q = lft
      if (rht <= _size && cmp(_tree[rht], _tree[q]) < 0) q += 1

      const x = _tree[q]
      if (cmp(_tree[i], x) <= 0) break

      _tree[q] = _tree[i]
      _tree[i] = x
      i = q
    }
  }

  function _up(index: number): void {
    for (let i = index; i > 1; ) {
      const q = i >> 1
      const x = _tree[q]
      if (cmp(x, _tree[i]) <= 0) break

      _tree[q] = _tree[i]
      _tree[i] = x
      i = q
    }
  }

  return {
    enqueue,
    dequeue,
    top,
    collect,
    size: () => _size,
    isEmpty: () => _size < 1,
  }
}

