export function Add(num1: number, num2: number): number {
  let result = 0
  for (; num1 > 0 && num2 > 0; ) {
    let a = num1 & -num1
    let b = num2 & -num2
    if (a <= b) {
      num1 ^= a
      for (; a & result; a <<= 1) result ^= a
      result ^= a
    } else {
      num2 ^= b
      for (; b & result; b <<= 1) result ^= b
      result ^= b
    }
  }

  if (num2 > 0) num1 = num2
  for (; num1 > 0; ) {
    let a = num1 & -num1
    num1 ^= a
    for (; a & result; a <<= 1) result ^= a
    result ^= a
  }
  return result
}

