  else if (str[0] === '-') {
    flag = true
    i += 1
  }

  if (i >= str.length) return 0
  const zero = '0'.codePointAt(0)
  for (; i < str.length; ++i) {
    const x = str.codePointAt(i) - zero
    if (x < 0 || x > 9) return 0
    result = result * 10 + x
  }
  return flag && result ? -result : result
}

