int ms[MAX_C];   // 单调栈

int solution(int N, int C) {
  memset(g, 0, sizeof(int) * (C + 1));

  for (int i = 0, V, W, M, ss, tt; i < N; ++i) {
    scanf("%d%d%d", &V, &W, &M);

    std::swap(g, h);
    for (int x = 0; x < V; ++x) {
      // 初始化单调栈
      ss = 0;
      tt = 1;
      ms[0] = 0;
      h[x] = g[x];

      for (int c = x + V, k = 1; c <= C; c += V, k += 1) {
        // 窗口长度最大为 M
        if (k - ms[ss] > M) ss += 1;

        // 单调栈中，栈底元素的值最大
        h[c] = std::max(g[c], g[x + ms[ss] * V] + (k - ms[ss]) * W);

        // 压栈
        for (; ss < tt; --tt) {
          int top = ms[tt - 1];
          if (g[x + top * V] + (k - top) * W > g[c]) break;
        }
        ms[tt++] = k;
      }
    }
  }
  return h[C];
}

