const int MAX_C = 20000 + 10;
const int MOD = 1e9 + 7;
int F[MAX_C], G[MAX_C];

int solution(int N, int C) {
  // Initialize.
  for (int c = 0; c <= C; ++c) {
    F[c] = 0;
    G[c] = 1;
  }

  for (int i = 0, V, W; i < N; ++i) {
    scanf("%d%d", &V, &W);
    for (int c = C; c >= V; --c) {
      int total = F[c - V] + W;
      if (F[c] < total) {
        F[c] = total;
        G[c] = G[c - V];
      } else if (F[c] == total) {
        G[c] = (G[c] + G[c - V]) % MOD;
      }
    }
  }
  return G[C];
}
